class Solution {
public:
    int shipWithinDays(vector<int>& weights, int days) {
        int left = 0, right = 0;
        for (int w : weights) {
            left = max(left, w);
            right += w;
        }
        while (left < right) {
            int mid = (left + right) / 2;
            if (canShip(weights, days, mid)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    bool canShip(vector<int>& weights, int days, int capacity) {
        int current = 0;
        int daysNeeded = 1;
        for (int w : weights) {
            if (current + w > capacity) {
                daysNeeded++;
                current = w;
            } else {
                current += w;
            }
        }
        return daysNeeded <= days;
    }
};

